import React from 'react';
import Icon from '../../../components/AppIcon';

const PricingBreakdown = ({ 
  dailyPrice, 
  rentalDays, 
  equipmentTotal, 
  platformCommission, 
  insuranceFee, 
  totalAmount 
}) => {
  const formatPrice = (price) => {
    return price?.toFixed(2);
  };

  // Calculate new commission structure
  const platformFee = equipmentTotal * 0.12; // 12% platform commission
  const paymentFee = (equipmentTotal * 0.015) + 0.25; // 1.5% + 0.25€ payment fees
  const totalFees = platformFee + paymentFee;
  const newTotalAmount = equipmentTotal + totalFees + (insuranceFee || 0);

  return (
    <div className="space-y-3">
      {/* Equipment Price */}
      <div className="flex justify-between items-center py-2">
        <div className="flex items-center gap-2">
          <Icon name="Package" size={18} className="text-muted-foreground" />
          <span className="text-sm text-foreground">
            {dailyPrice?.toFixed(2)} € × {rentalDays} jour{rentalDays > 1 ? 's' : ''}
          </span>
        </div>
        <span className="font-medium text-foreground">
          {formatPrice(equipmentTotal)} €
        </span>
      </div>

      {/* Platform Commission */}
      <div className="flex justify-between items-center py-2">
        <div className="flex items-center gap-2">
          <Icon name="Percent" size={18} className="text-muted-foreground" />
          <span className="text-sm text-muted-foreground">
            Commission plateforme (12%)
          </span>
        </div>
        <span className="text-sm text-muted-foreground">
          {formatPrice(platformFee)} €
        </span>
      </div>

      {/* Payment Fees */}
      <div className="flex justify-between items-center py-2">
        <div className="flex items-center gap-2">
          <Icon name="CreditCard" size={18} className="text-muted-foreground" />
          <span className="text-sm text-muted-foreground">
            Frais de paiement (1,5% + 0,25 €)
          </span>
        </div>
        <span className="text-sm text-muted-foreground">
          {formatPrice(paymentFee)} €
        </span>
      </div>

      {/* Insurance Fee */}
      {insuranceFee > 0 && (
        <div className="flex justify-between items-center py-2">
          <div className="flex items-center gap-2">
            <Icon name="ShieldCheck" size={18} className="text-success" />
            <span className="text-sm text-success-foreground">
              Assurance tous risques
            </span>
          </div>
          <span className="text-sm text-success-foreground">
            {formatPrice(insuranceFee)} €
          </span>
        </div>
      )}

      {/* Divider */}
      <div className="border-t border-border my-3" />

      {/* Total */}
      <div className="flex justify-between items-center py-2">
        <span className="text-lg font-semibold text-foreground">
          Total
        </span>
        <span className="text-xl font-bold text-primary">
          {formatPrice(newTotalAmount)} €
        </span>
      </div>

      {/* Info Note */}
      {rentalDays > 0 && (
        <div className="mt-4 p-3 bg-muted/50 rounded-md">
          <p className="text-xs text-muted-foreground">
            <Icon name="Info" size={14} className="inline mr-1" />
            Le montant total sera débité lors de la confirmation de la réservation par le propriétaire.
          </p>
        </div>
      )}
    </div>
  );
};

export default PricingBreakdown;